member.example:
Bind the Object name property using a serialized binder field — the target is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private ObjectNameBinder _objectName;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public string _objectName;
    }


Bind the Object name property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private Object _object;
        
        private ObjectNameBinder ObjectName =>
            new(_object);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public string _objectName;
    }
